#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char A[500005];
    char B[500005];
    while (T--) {
        scanf("%s", A);
        scanf("%s", B);
        int N = strlen(A);
        int a1 = 0, b1 = 0;
        for (int i = 0; i < N; ++i) {
            if (A[i] == '1') ++a1;
            if (B[i] == '1') ++b1;
        }
        int a0 = N - a1;
        int b0 = N - b1;
        int K = (a1 < b0 ? a1 : b0) + (a0 < b1 ? a0 : b1);
        for (int i = 0; i < K; ++i) putchar('1');
        for (int i = K; i < N; ++i) putchar('0');
        putchar('\n');
    }
    return 0;
}

