    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        string A,B; cin>>A>>B;
        int N = A.size();
        int a1 = 0, b1 = 0;
        for(char c: A) if(c=='1') ++a1;
        for(char c: B) if(c=='1') ++b1;
        int a0 = N - a1, b0 = N - b1;
        int K = min(a1,b0) + min(a0,b1);
        cout << string(K,'1') << string(N-K,'0') << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            String A = br.readLine().trim();
            String B = br.readLine().trim();
            int N = A.length();
            int a1 = 0, b1 = 0;
            for (int i = 0; i < N; i++) {
                if (A.charAt(i) == '1') a1++;
                if (B.charAt(i) == '1') b1++;
            }
            int a0 = N - a1, b0 = N - b1;
            int K = Math.min(a1, b0) + Math.min(a0, b1);
            for (int i = 0; i < K; i++) out.append('1');
            for (int i = K; i < N; i++) out.append('0');
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

